import React, { useEffect, useState } from 'react';
import axios from 'axios';

const EventList = () => {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Заменить URL на свой backend
    axios.get('http://localhost:8000/api/events/') // или правильный путь к API
      .then(response => {
        setEvents(response.data); // Данные получены
        setLoading(false); // Остановить загрузку
      })
      .catch(error => {
        setError('Ошибка загрузки данных');
        setLoading(false);
      });
  }, []);

  if (loading) return <div>Загрузка...</div>;
  if (error) return <div>{error}</div>;

  return (
    <div>
      <h1>Список мероприятий</h1>
      <ul>
        {events.map(event => (
          <li key={event.id}>
            <strong>{event.title}</strong><br />
            {event.description}<br />
            <em>{new Date(event.start_time).toLocaleString()}</em><br />
            <em>{new Date(event.end_time).toLocaleString()}</em>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default EventList;
